@module eventMeta  src=eventMeta.lua  loc=126  sha=54e469d  mode=chunk  self=eventMeta
@deps ps

# Invariants & contracts
  @invariant  per-event metadata keyed by POOL guid, not take — every pooled instance shares one blob  @ 3
  @invariant  'ctm.<guid>.' slots: kb=live bucket set, e.<b>={[uuid]=fields}, b=uuid//64  @ 4
  @invariant  one writer per guid — bucket read-modify-write loses concurrent same-guid updates  @ 5
  @invariant  stores opaque field tables; the strip (which fields are metadata) is mm's, never inspected here  @ 6
  @contract  a nil guid is a no-op/empty everywhere — a take with no derivable pool carries no persisted metadata  @ 7

# Imports
  @require util = 'util'  @ 8
  @require perf = 'perf'  @ 9

# Private state
  @state BUCKET = 64  @ 13   -- uuids per entry bucket; an edit rewrites its bucket, never the pool
  @state eventMeta = {}  @ 27
  @state fire = util.installHooks(eventMeta)  @ 28

# Private functions
  @fn kbSlot(guid)  @ 15
  @fn bucketSlot(guid, b)  @ 16
  @fn readKb(guid)  @ 20
      -- The bucket is both the data and its own enumeration (projext has no
      -- enumerate-by-prefix); kb tracks which buckets exist. See docs/eventMeta.md § Granularity.
  @fn readBucket(guid, b)  @ 21
  @fn writeKb(guid, kb)  @ 23-25

# Public API (eventMeta:*)
  @api eventMeta:load(guid)  @ 44-51
      @contract  { [uuid:int] = fields }; empty table if the guid has no metadata  @ 43
  @api eventMeta:flush(guid, dirty, deleted)  @ 55-85
      @contract  batched incremental persist: applies dirty={[uuid]=fields} + deleted={[uuid]=true}  @ 53
      @contract  per-modify hot path: read-modify-writes touched buckets only, never the whole pool  @ 54
  @api eventMeta:saveAll(guid, byUuid)  @ 88-109
      @contract  replaces the pool's whole metadata with byUuid={[uuid]=fields}; sweeps uuids no longer present  @ 87
  @api eventMeta:copyPool(srcGuid, dstGuid)  @ 112-115
      @contract  forks srcGuid's metadata onto dstGuid (an unpooled clone mints a fresh pool; this seeds it)  @ 111
  @api eventMeta:dropPool(guid)  @ 118-124
      @contract  forever-deletes a pool's metadata (deleteSlot's keeper removal)  @ 117

# Signals emitted (via util.installHooks)
  @emits poolsRewound   -- { guids = set }; a REAPER undo rewound these pools' metadata slots   @ 40

# Uses (outbound edges)
  @use call    perf.count  @ flush:83 saveAll:107
  @use call    perf.start  @ flush:67 saveAll:90
  @use call    perf.stop  @ flush:84 saveAll:108
  @use call    ps:assign  @ writeKb:24 flush:75,78 saveAll:99,103 dropPool:121,123
  @use call    ps:get  @ readKb:20 readBucket:21
  @use call    util.installHooks  @ 28
  @use require perf  @ 9
  @use require util  @ 8
  @use sub     ps:projectRewound  @ 34

# Fields (r read / w write incl. constructor keys)
  @field r REMOVE  @ writeKb:24 flush:78 saveAll:99 dropPool:121,123
  @field w guids  @ 40
  @field w prefixes  @ 31
  @field r ps  @ 11
